import type { EntityKind, TokenEntry } from '../types.js';
import type {
  Tokenizer,
  TokenVault,
  TokenizeOptions,
  TokenizeResult,
  TokenizedEntity,
} from '../interfaces.js';
import type { RegexDetector } from './detectors.js';
import type { HttpClient } from '../http.js';
import { DEFAULT_DETECTORS } from './patterns.js';
import { scanForTokens, detokenizeDeep } from './detokenize.js';
import { normalize } from '../vault/memory.js';
import {
  extractEntitiesFromCloud,
  extractEntitiesFromMl,
  type MlEntity,
} from './ml-entity-extractor.js';

interface MlMeta {
  label?: string | null;
  category?: string | null;
  sensitivity?: MlEntity['sensitivity'];
  risk_reason?: string | null;
  validated_by?: string[] | null;
}

interface Match {
  detector: RegexDetector;
  raw: string;
  index: number;
  length: number;
  /** v3 metadata propagated from ml.privent.ai when a match overlaps an ML entity. */
  mlMeta?: MlMeta;
  /** Pre-allocated token from a `findOrCreateBatch` call. Set only when the
   *  vault supports batch find-or-create (e.g. CloudTokenVault). */
  token?: string;
}

function pickMlMeta(ent: MlEntity): MlMeta {
  const meta: MlMeta = {};
  if (ent.label !== undefined) meta.label = ent.label;
  if (ent.category !== undefined) meta.category = ent.category;
  if (ent.sensitivity !== undefined) meta.sensitivity = ent.sensitivity;
  if (ent.risk_reason !== undefined) meta.risk_reason = ent.risk_reason;
  if (ent.validated_by !== undefined) meta.validated_by = ent.validated_by;
  return meta;
}

export class HybridTokenizer implements Tokenizer {
  private readonly detectors: readonly RegexDetector[];

  constructor(
    detectors: readonly RegexDetector[] = DEFAULT_DETECTORS,
    private readonly http?: HttpClient,
    /**
     * Optional dedicated client for a self-hosted privent-ml service. When
     * present, entity extraction goes to `${mlBaseUrl}/classify` instead of
     * the Cloud `/v1/risk/score` path.
     */
    private readonly mlHttp?: HttpClient,
  ) {
    this.detectors = detectors;
  }

  async tokenize(
    text: string,
    vault: TokenVault,
    opts: TokenizeOptions = {},
  ): Promise<TokenizeResult> {
    const mode = opts.entityExtractionMode ?? 'auto';
    const allowSet = new Set(opts.allowList ?? []);
    const denySet = new Set(opts.denyList ?? []);

    // Select which detectors to run based on `kinds` option.
    const activeDetectors = filterDetectors(this.detectors, opts);

    // Regex pass — collect all matches across all detectors.
    let matches: Match[] = [];
    for (const detector of activeDetectors) {
      const re = new RegExp(detector.regex.source, 'g');
      for (const m of text.matchAll(re)) {
        if (m.index == null) continue;
        const raw = m[0];
        if (detector.validate && !detector.validate(raw)) continue;
        matches.push({ detector, raw, index: m.index, length: raw.length });
      }
    }

    // Apply allow/deny lists.
    matches = matches.filter((m) => {
      const normalized = m.detector.normalize(m.raw);
      if (allowSet.has(m.raw) || allowSet.has(normalized)) return false;
      return true;
    });
    for (const raw of denySet) {
      // Force-add denyList values not caught by detectors (kind: UNKNOWN).
      if (!matches.some((m) => m.raw === raw)) {
        const idx = text.indexOf(raw);
        if (idx !== -1) {
          matches.push({
            detector: {
              kind: 'UNKNOWN',
              regex: /(?!)/g,
              normalize: (v) => v,
              confidence: 1,
            },
            raw,
            index: idx,
            length: raw.length,
          });
        }
      }
    }

    // Remove overlapping spans — longest span wins.
    matches = removeOverlaps(matches);

    // Optional ML pass to enrich entity labels (fails open).
    // Prefer the dedicated privent-ml client when present, otherwise fall
    // back to the Privent Cloud client.
    const mlClient = this.mlHttp ?? this.http;
    let documentLang: string | null | undefined;
    let extractionMeta: TokenizeResult['extractionMeta'];
    if (mode !== 'regex' && mlClient != null) {
      const bootstrap = matches.map((m) => ({
        kind: m.detector.kind,
        value: m.raw,
        span: [m.index, m.index + m.length] as [number, number],
        confidence: m.detector.confidence,
      }));
      const mlRequest = {
        text,
        bootstrap_entities: bootstrap,
      };
      const mlResult = this.mlHttp != null
        ? await extractEntitiesFromMl(this.mlHttp, mlRequest)
        : await extractEntitiesFromCloud(mlClient, mlRequest);

      if (mlResult != null) {
        // ML response order is not guaranteed stable across model runs; sort
        // before merge so removeOverlaps() decisions are deterministic.
        // `mlResult.entities` is normalised to `[]` by both extractors, but
        // guard with `?? []` so any future caller that bypasses them stays safe.
        const stableEntities = [...(mlResult.entities ?? [])].sort(
          (a, b) =>
            a.span[0] - b.span[0] ||
            a.span[1] - b.span[1] ||
            a.kind.localeCompare(b.kind) ||
            a.value.localeCompare(b.value),
        );
        // Two passes: (1) enrich existing regex matches with overlapping ML
        // metadata (label/sensitivity/etc.), (2) add new model-sourced spans
        // that no regex match covers.
        for (const ent of stableEntities) {
          const overlapping = matches.find(
            (m) => ent.span[0] < m.index + m.length && ent.span[1] > m.index,
          );
          if (overlapping != null) {
            overlapping.mlMeta = pickMlMeta(ent);
            continue;
          }
          if (ent.source === 'model') {
            matches.push({
              detector: {
                kind: ent.kind,
                regex: /(?!)/g,
                normalize: (v) => v.trim(),
                confidence: ent.confidence,
              },
              raw: ent.value,
              index: ent.span[0],
              length: ent.value.length,
              mlMeta: pickMlMeta(ent),
            });
          }
        }
        matches = removeOverlaps(matches);

        if (mlResult.document_lang !== undefined) {
          documentLang = mlResult.document_lang;
        }
        if (mlResult.extraction_meta != null) {
          extractionMeta = {
            engine: mlResult.extraction_meta.engine,
            latencyMs: mlResult.extraction_meta.latency_ms,
            buildSignature: mlResult.extraction_meta.build_signature,
          };
        } else if (mlResult.extraction_meta === null) {
          extractionMeta = null;
        }
      }
    }

    // Bulk find-or-create when the vault supports it (e.g. CloudTokenVault).
    // Folds N round-trips into one HTTP call; falls back to the per-entity
    // path below when the vault doesn't implement the optional method.
    if (typeof vault.findOrCreateBatch === 'function' && matches.length > 0) {
      const batched = await vault.findOrCreateBatch(
        matches.map((m) => ({
          kind: m.detector.kind,
          value: normalize(m.detector.kind, m.raw),
        })),
      );
      matches.forEach((m, i) => {
        const row = batched[i];
        if (row != null) m.token = row.token;
      });
    }

    // Replace right-to-left to keep span indices valid during substitution.
    matches.sort((a, b) => b.index - a.index);

    let result = text;
    const entities: TokenizedEntity[] = [];

    for (const match of matches) {
      const { detector, raw, index, length, mlMeta } = match;
      const normalizedValue = normalize(detector.kind, raw);

      let token: string;
      if (match.token != null) {
        token = match.token;
      } else {
        // Deterministic: reuse token if same value was already seen in this session.
        const existing = await vault.findByValue(normalizedValue, detector.kind);
        if (existing != null) {
          token = existing.token;
        } else {
          token = await mint(vault, detector.kind, normalizedValue, raw);
        }
      }

      result = result.slice(0, index) + token + result.slice(index + length);
      const entity: TokenizedEntity = {
        token,
        kind: detector.kind,
        confidence: detector.confidence,
        span: [index, index + length],
      };
      if (mlMeta != null) {
        if (mlMeta.label !== undefined) entity.label = mlMeta.label;
        if (mlMeta.category !== undefined) entity.category = mlMeta.category;
        if (mlMeta.sensitivity !== undefined) entity.sensitivity = mlMeta.sensitivity;
        if (mlMeta.risk_reason !== undefined) entity.riskReason = mlMeta.risk_reason;
        if (mlMeta.validated_by !== undefined) entity.validatedBy = mlMeta.validated_by;
      }
      entities.push(entity);
    }

    // Restore entities in left-to-right order.
    entities.sort((a, b) => a.span[0] - b.span[0]);

    const out: TokenizeResult = { tokenizedText: result, entities };
    if (documentLang !== undefined) out.documentLang = documentLang;
    if (extractionMeta !== undefined) out.extractionMeta = extractionMeta;
    return out;
  }

  async detokenize(value: unknown, vault: TokenVault): Promise<unknown> {
    return detokenizeDeep(value, vault);
  }

  scanForTokens(value: unknown): Iterable<string> {
    return scanForTokens(value);
  }
}

async function mint(
  vault: TokenVault,
  kind: EntityKind,
  normalizedValue: string,
  raw: string,
): Promise<string> {
  const counter = await vault.nextCounter(kind);
  const token = `[${kind}_${String(counter).padStart(3, '0')}]`;
  const entry: TokenEntry = {
    token,
    value: raw,
    kind,
    sessionId: vault.sessionId,
    createdAt: Date.now(),
  };
  await vault.store(entry);
  return token;
}

function filterDetectors(
  detectors: readonly RegexDetector[],
  opts: TokenizeOptions,
): RegexDetector[] {
  const base = opts.kinds != null
    ? detectors.filter((d) => (opts.kinds as string[]).includes(d.kind))
    : [...detectors];

  if (opts.customPatterns) {
    for (const cp of opts.customPatterns) {
      base.push({
        kind: cp.kind,
        regex: cp.regex,
        normalize: (v) => v.trim(),
        confidence: cp.confidence ?? 0.9,
      });
    }
  }

  return base;
}

function removeOverlaps(matches: Match[]): Match[] {
  // Sort by start position; longer span wins on ties; final tiebreak on kind
  // then raw value to make ordering total (ML response ordering can otherwise
  // produce different but spec-equivalent outputs across runs).
  matches.sort(
    (a, b) =>
      a.index - b.index ||
      b.length - a.length ||
      a.detector.kind.localeCompare(b.detector.kind) ||
      a.raw.localeCompare(b.raw),
  );

  const result: Match[] = [];
  let lastEnd = -1;

  for (const m of matches) {
    if (m.index >= lastEnd) {
      result.push(m);
      lastEnd = m.index + m.length;
    }
  }

  return result;
}
