import { z } from 'zod';

const UuidV4 = z.string().uuid();
const Iso8601 = z.string().datetime({ offset: true });

/**
 * Framework that emitted the audit event.
 * Open string (max 30 chars) — strict enum was changed to a free-form string
 * in v1.x to support framework adapters added without an SDK release
 * (LangGraph, CrewAI, MCP, etc.). Backend keeps a soft-validation accepted-list
 * for typo detection; ingest still accepts any string.
 */
export const FrameworkEnum = z.string().min(1).max(30);
export type FrameworkV1 = z.infer<typeof FrameworkEnum>;

/**
 * Reason for an agent_handoff event. Open enum on the wire; SDK clients should
 * pick from this list when emitting.
 */
export const HandoffReasonEnum = z.enum([
  'delegation',
  'subgraph_call',
  'tool_invocation',
  'webhook_trigger',
  'other',
]);
export type HandoffReasonV1 = z.infer<typeof HandoffReasonEnum>;

/**
 * Canonical 4-tier severity vocabulary shared with privent-ml and the
 * backend severity taxonomy. Replaces the legacy `policy_decision`
 * (BLOCK/WARN/ALLOW) wire field that retired with the severity refactor.
 */
export const RiskLevelEnum = z.enum(['LOW', 'MEDIUM', 'HIGH', 'CRITICAL']);
export type RiskLevelV1 = z.infer<typeof RiskLevelEnum>;

/**
 * Audit event metadata is JSON-shaped but constrained:
 * - No raw entity values (use 8-char sha256 fingerprint instead).
 * - Authorization headers, password/secret/apiKey/token field names are scrubbed
 *   by CloudAuditLogger before buffer + before disk spool (defense in depth).
 *
 * Schema-wise this is `record<string, unknown>` to permit nested structure.
 * Privacy invariants are enforced in code (audit-logger.ts) and tested by
 * audit-spool-leak.test.ts (CP-5).
 */
const Metadata = z.record(z.string(), z.unknown());

const WebhookConfigSchema = z
  .object({
    url: z.string().min(1).max(2048),
    method: z.string().max(10).optional(),
    auth_scheme: z.string().max(64).optional(),
    content_type: z.string().max(120).optional(),
  })
  .strict();

const SinkConfigSchema = z
  .object({
    sink_key: z.string().min(1).max(500),
    host: z.string().min(1).max(255),
    trusted: z.boolean().optional(),
    tls_version: z.string().max(16).optional(),
    cert_fingerprint: z.string().max(128).optional(),
    added_by_user_id: z.string().uuid().optional(),
  })
  .strict();

const VaultConfigSchema = z
  .object({
    name: z.string().min(1).max(255),
    region: z.string().max(64).optional(),
    retention_days: z.number().int().nonnegative().optional(),
    detection_mode: z.string().max(64).optional(),
    detection_version: z.string().max(64).optional(),
  })
  .strict();

const CronConfigSchema = z
  .object({
    cron_expression: z.string().min(1).max(120),
    timezone: z.string().max(64).optional(),
  })
  .strict();

/**
 * Single audit event. `event_id` is a UUID for idempotency on the ingest endpoint.
 */
export const AuditEventV1Schema = z
  .object({
    event_id: UuidV4,
    type: z.string().min(1).max(64),
    trace_id: UuidV4,
    session_id: UuidV4,
    timestamp: Iso8601,
    framework: FrameworkEnum,
    workflow_id: z.string().max(128).optional(),
    node_id: z.string().max(128).optional(),
    metadata: Metadata,
    latency_ms: z.number().int().nonnegative().optional(),
    error_type: z.string().max(64).optional(),
    node_name: z.string().max(255).optional(),
    http_status: z.number().int().optional(),
    webhook_config: WebhookConfigSchema.optional(),
    sink_config: SinkConfigSchema.optional(),
    vault_config: VaultConfigSchema.optional(),
    cron_config: CronConfigSchema.optional(),
    // ── Trust Map / agent_handoff fields (all optional; see
    //    docs/trust-map-event-shape.md in privent-frontend) ──
    from_agent_id: z.string().max(64).optional(),
    from_agent_name: z.string().max(255).optional(),
    target_agent_id: z.string().max(64).optional(),
    target_agent_name: z.string().max(255).optional(),
    target_sink_id: z.string().max(500).optional(),
    reason: HandoffReasonEnum.optional(),
    payload_token_count: z.number().int().nonnegative().optional(),
    /**
     * 4-tier severity (LOW/MEDIUM/HIGH/CRITICAL). Replaces the legacy
     * `policy_decision` (BLOCK/WARN/ALLOW) wire field — backend
     * `audit-ingest` now persists `risk_level` exclusively for AGENT_SDK
     * callers and dashboards aggregate severity directly.
     */
    risk_level: RiskLevelEnum.optional(),
    parent_event_id: UuidV4.optional(),
    branch_id: z.string().max(64).optional(),
    hop_depth: z.number().int().positive().optional(),
  })
  .strict();
export type AuditEventV1 = z.infer<typeof AuditEventV1Schema>;

/**
 * POST /v1/audit/events — batch upload, max 200 events per request.
 */
export const AuditBatchRequestSchema = z
  .object({
    events: z.array(AuditEventV1Schema).min(1).max(200),
  })
  .strict();
export type AuditBatchRequestV1 = z.infer<typeof AuditBatchRequestSchema>;

/**
 * Backend may acknowledge ingest with the count of accepted events; SDK does
 * not require any field, but a stable shape avoids parse churn.
 */
export const AuditBatchResponseSchema = z
  .object({
    accepted: z.number().int().nonnegative(),
  })
  .strict();
export type AuditBatchResponseV1 = z.infer<typeof AuditBatchResponseSchema>;
