import type { EntityKind } from '../types.js';
import type { HttpClient } from '../http.js';

/**
 * Sensitivity tier emitted by the v3 ML extraction surface
 * (NuExtract + validators path on ml.privent.ai).
 */
export type MlSensitivity = 'low' | 'medium' | 'high' | 'critical';

export interface MlEntity {
  kind: EntityKind;
  value: string;
  span: [number, number];
  confidence: number;
  /** `"model"` when NER head is active; `"regex"` for Phase-A regex-backed extraction. */
  source: 'model' | 'regex';
  /** Human-readable v3 label, e.g. "date of birth". Null on legacy presidio path. */
  label?: string | null;
  /** v3 category bucket: pii | financial | secret | health | legal | code | strategy | other. */
  category?: string | null;
  /** v3 sensitivity tier. */
  sensitivity?: MlSensitivity | null;
  /** v3 free-text reason, e.g. "Validated by dob_date". */
  risk_reason?: string | null;
  /** v3 validator ids that fired for this entity. */
  validated_by?: string[] | null;
}

export interface MlExtractionRequest {
  text: string;
  lang?: string;
  bootstrap_entities?: Array<{ kind: EntityKind; value: string; span: [number, number]; confidence: number }>;
  include_entities: true;
}

/**
 * v3 extraction telemetry returned by ml.privent.ai. Optional because the
 * legacy presidio path returns this as `null`.
 */
export interface MlExtractionMeta {
  engine: string;
  latency_ms: number;
  build_signature: string;
}

export interface MlExtractionResponse {
  risk_score: number;
  risk_level: string;
  categories: Partial<Record<EntityKind, number>>;
  entities: MlEntity[];
  model: string;
  latency_ms?: number;
  /** Detected document language (ISO-639-1) — v3 only. */
  document_lang?: string | null;
  /** Engine telemetry — v3 only. */
  extraction_meta?: MlExtractionMeta | null;
}

/**
 * Calls Privent Cloud `/v1/risk/score` with `include_entities: true`.
 * Fails open on any error — callers fall back to regex-only detection.
 * This is a Week 1 foundation; the actual cloud backend ships in Week 3.
 */
export async function extractEntitiesFromCloud(
  http: HttpClient,
  request: Omit<MlExtractionRequest, 'include_entities'>,
  signal?: AbortSignal,
): Promise<MlExtractionResponse | null> {
  try {
    const reqOpts = {
      method: 'POST' as const,
      body: { ...request, include_entities: true } satisfies MlExtractionRequest,
      ...(signal != null && { signal }),
    };
    const raw = await http.request<MlExtractionResponse & { entities: MlEntity[] | null }>(
      '/v1/risk/score',
      reqOpts,
    );
    // Cloud `/v1/risk/score` returns `entities: null` when the upstream ML
    // call ran without include_entities or fell through to a path that
    // skipped extraction. Normalise to `[]` so downstream `for…of` /
    // `[...mlResult.entities]` consumers don't crash on null.
    return { ...raw, entities: raw.entities ?? [] };
  } catch {
    // Fail-open: ML service unavailable → caller uses regex-only results.
    return null;
  }
}

/**
 * Shape returned by privent-ml's `POST /classify` endpoint. Differs from the
 * Cloud `/v1/risk/score` response: `categories` is a plain `string[]` (not a
 * weighted record) and `model` is not echoed. v3 paths additionally return
 * per-entity label/category/sensitivity plus document_lang + extraction_meta.
 */
interface MlClassifyResponse {
  risk_score: number;
  risk_level: string;
  categories: string[];
  entities: MlEntity[] | null;
  document_lang?: string | null;
  extraction_meta?: MlExtractionMeta | null;
}

/**
 * Calls a self-hosted privent-ml service at `${baseUrl}/classify` with
 * `include_entities: true`. Used for on-prem NuExtract + validators extraction.
 * Fails open on any error — callers fall back to regex-only detection.
 */
export async function extractEntitiesFromMl(
  http: HttpClient,
  request: Omit<MlExtractionRequest, 'include_entities'>,
  signal?: AbortSignal,
): Promise<MlExtractionResponse | null> {
  try {
    const reqOpts = {
      method: 'POST' as const,
      body: { ...request, include_entities: true } satisfies MlExtractionRequest,
      ...(signal != null && { signal }),
    };
    const raw = await http.request<MlClassifyResponse>('/classify', reqOpts);
    return {
      risk_score: raw.risk_score,
      risk_level: raw.risk_level,
      categories: {},
      entities: raw.entities ?? [],
      model: 'privent-ml',
      ...(raw.document_lang !== undefined && { document_lang: raw.document_lang }),
      ...(raw.extraction_meta !== undefined && { extraction_meta: raw.extraction_meta }),
    };
  } catch {
    return null;
  }
}
