/**
 * Per-host circuit breaker. Mirrors the privent-backend CB pattern
 * (risk.service.ts:298) but instance-local, in-process, no Redis.
 *
 * States:
 *   - CLOSED: normal traffic; failures are recorded.
 *   - OPEN: requests are rejected for `openDurationMs`; no upstream call.
 *   - HALF_OPEN: one probe is allowed; success → CLOSED, failure → OPEN again.
 *
 * Only counts results within a sliding `windowMs`; transitions only when
 * `samples >= minSamples` to avoid flapping on low traffic.
 *
 * The breaker holds no timers — `canRequest()` lazily transitions state
 * by reading `Date.now()`. Suitable for hot paths.
 */
export interface CircuitBreakerOptions {
  /** Sliding window for failure-rate calculation (ms). Default 30_000. */
  windowMs?: number;
  /** Failure ratio (0..1) above which the breaker opens. Default 0.5. */
  failureThreshold?: number;
  /** Minimum samples in the window before any transition. Default 5. */
  minSamples?: number;
  /** How long the breaker stays OPEN before allowing a probe. Default 30_000. */
  openDurationMs?: number;
  /** Time source for tests. Defaults to Date.now. */
  now?: () => number;
}

export type CircuitState = 'CLOSED' | 'OPEN' | 'HALF_OPEN';

interface Sample {
  ok: boolean;
  at: number;
}

export class CircuitBreaker {
  private state: CircuitState = 'CLOSED';
  private samples: Sample[] = [];
  /** Wall-clock ts when OPEN was entered; used to schedule HALF_OPEN. */
  private openedAt = 0;
  /** True iff a probe is in flight in HALF_OPEN. Blocks concurrent probes. */
  private probeInFlight = false;
  private readonly windowMs: number;
  private readonly failureThreshold: number;
  private readonly minSamples: number;
  private readonly openDurationMs: number;
  private readonly now: () => number;

  constructor(opts: CircuitBreakerOptions = {}) {
    this.windowMs = opts.windowMs ?? 30_000;
    this.failureThreshold = opts.failureThreshold ?? 0.5;
    this.minSamples = opts.minSamples ?? 5;
    this.openDurationMs = opts.openDurationMs ?? 30_000;
    this.now = opts.now ?? Date.now;
  }

  /**
   * Returns true iff a request may be issued. As a side effect, transitions
   * OPEN → HALF_OPEN when the open duration has elapsed and reserves the
   * probe slot.
   */
  canRequest(): boolean {
    if (this.state === 'CLOSED') return true;
    if (this.state === 'OPEN') {
      if (this.now() - this.openedAt >= this.openDurationMs) {
        this.state = 'HALF_OPEN';
        this.probeInFlight = false;
      } else {
        return false;
      }
    }
    // HALF_OPEN: only one in-flight probe at a time.
    if (this.probeInFlight) return false;
    this.probeInFlight = true;
    return true;
  }

  recordSuccess(): void {
    this.append({ ok: true, at: this.now() });
    if (this.state === 'HALF_OPEN') {
      this.state = 'CLOSED';
      this.samples = []; // fresh window after recovery
    }
    this.probeInFlight = false;
  }

  recordFailure(): void {
    this.append({ ok: false, at: this.now() });
    if (this.state === 'HALF_OPEN') {
      this.openedAt = this.now();
      this.state = 'OPEN';
      this.probeInFlight = false;
      return;
    }
    if (this.state === 'CLOSED' && this.shouldOpen()) {
      this.openedAt = this.now();
      this.state = 'OPEN';
    }
  }

  /** Inspect current state without mutation. Test/observability use. */
  getState(): CircuitState {
    return this.state;
  }

  private append(s: Sample): void {
    this.samples.push(s);
    this.gc();
  }

  private gc(): void {
    const cutoff = this.now() - this.windowMs;
    while (this.samples.length > 0 && this.samples[0]!.at < cutoff) {
      this.samples.shift();
    }
  }

  private shouldOpen(): boolean {
    this.gc();
    if (this.samples.length < this.minSamples) return false;
    const failures = this.samples.reduce((n, s) => n + (s.ok ? 0 : 1), 0);
    return failures / this.samples.length >= this.failureThreshold;
  }
}

/**
 * Per-host registry. Key by `new URL(baseUrl).host`. Lazy-allocates a breaker
 * on first access. Tests can swap with a fresh registry.
 */
export class CircuitBreakerRegistry {
  private readonly map = new Map<string, CircuitBreaker>();
  constructor(private readonly factoryOpts: CircuitBreakerOptions = {}) {}

  for(host: string): CircuitBreaker {
    let cb = this.map.get(host);
    if (cb == null) {
      cb = new CircuitBreaker(this.factoryOpts);
      this.map.set(host, cb);
    }
    return cb;
  }

  /** Test helper. */
  reset(): void {
    this.map.clear();
  }
}
