/**
 * Wire serializer for audit events.
 *
 * Bridges the developer-facing `AuditEvent` (camelCase, numeric timestamp,
 * deprecated `'manual'` framework) and the v1 ingest contract
 * (`AuditEventV1Schema`, snake_case, ISO8601 timestamp, no `'manual'`).
 *
 * Responsibilities:
 *   - Generate `event_id` (UUIDv4) for backend idempotency.
 *   - Map every camelCase top-level field to snake_case.
 *   - Convert `timestamp` (ms) → ISO8601 with offset.
 *   - Coerce `framework: 'manual'` → `'sdk'`.
 *   - Validate the result against `AuditEventV1Schema` and throw on failure.
 *
 * Spool replay: events serialized once and persisted to disk by
 * `CloudAuditLogger.spoolBatch()` carry `__wire_serialized: true` so the
 * replay path can detect and skip re-serialization, preserving the original
 * `event_id` for idempotent retries.
 */

import type { AuditEvent } from '../interfaces.js';
import {
  AuditEventV1Schema,
  type AuditEventV1,
  type FrameworkV1,
} from '../contracts/v1/audit.js';

/**
 * Coerces the in-memory framework name to a wire-safe string. v1 schema accepts
 * any 1-30 char string, so we only need to translate the deprecated `'manual'`
 * alias; anything else passes through verbatim (supports future adapter names
 * like `'mcp-server'` without an SDK release).
 */
function frameworkForWire(framework: AuditEvent['framework']): FrameworkV1 {
  if (framework === 'manual') return 'sdk';
  return framework;
}

export interface SerializedSpoolRecord extends AuditEventV1 {
  __wire_serialized: true;
}

export function isSerializedSpoolRecord(
  value: unknown,
): value is SerializedSpoolRecord {
  return (
    value != null &&
    typeof value === 'object' &&
    (value as { __wire_serialized?: unknown }).__wire_serialized === true
  );
}

/**
 * Translate an in-memory `AuditEvent` to the v1 wire shape.
 * Throws on schema validation failure — caller decides whether to drop the
 * single event or propagate.
 */
export function serializeForWire(event: AuditEvent): AuditEventV1 {
  const wire: AuditEventV1 = {
    event_id: crypto.randomUUID(),
    type: event.type,
    trace_id: event.traceId,
    session_id: event.sessionId,
    timestamp: new Date(event.timestamp).toISOString(),
    framework: frameworkForWire(event.framework),
    ...(event.workflowId != null ? { workflow_id: event.workflowId } : {}),
    ...(event.nodeId != null ? { node_id: event.nodeId } : {}),
    metadata: event.metadata ?? {},
    ...(event.latencyMs != null ? { latency_ms: event.latencyMs } : {}),
    ...(event.errorType != null ? { error_type: event.errorType } : {}),
    ...(event.nodeName != null ? { node_name: event.nodeName } : {}),
    ...(event.httpStatus != null ? { http_status: event.httpStatus } : {}),
    ...(event.webhookConfig != null
      ? {
          webhook_config: {
            url: event.webhookConfig.url,
            ...(event.webhookConfig.method != null
              ? { method: event.webhookConfig.method }
              : {}),
            ...(event.webhookConfig.authScheme != null
              ? { auth_scheme: event.webhookConfig.authScheme }
              : {}),
            ...(event.webhookConfig.contentType != null
              ? { content_type: event.webhookConfig.contentType }
              : {}),
          },
        }
      : {}),
    ...(event.sinkConfig != null
      ? {
          sink_config: {
            sink_key: event.sinkConfig.sinkKey,
            host: event.sinkConfig.host,
            ...(event.sinkConfig.trusted != null
              ? { trusted: event.sinkConfig.trusted }
              : {}),
            ...(event.sinkConfig.tlsVersion != null
              ? { tls_version: event.sinkConfig.tlsVersion }
              : {}),
            ...(event.sinkConfig.certFingerprint != null
              ? { cert_fingerprint: event.sinkConfig.certFingerprint }
              : {}),
            ...(event.sinkConfig.addedByUserId != null
              ? { added_by_user_id: event.sinkConfig.addedByUserId }
              : {}),
          },
        }
      : {}),
    ...(event.vaultConfig != null
      ? {
          vault_config: {
            name: event.vaultConfig.name,
            ...(event.vaultConfig.region != null
              ? { region: event.vaultConfig.region }
              : {}),
            ...(event.vaultConfig.retentionDays != null
              ? { retention_days: event.vaultConfig.retentionDays }
              : {}),
            ...(event.vaultConfig.detectionMode != null
              ? { detection_mode: event.vaultConfig.detectionMode }
              : {}),
            ...(event.vaultConfig.detectionVersion != null
              ? { detection_version: event.vaultConfig.detectionVersion }
              : {}),
          },
        }
      : {}),
    ...(event.cronConfig != null
      ? {
          cron_config: {
            cron_expression: event.cronConfig.cronExpression,
            ...(event.cronConfig.timezone != null
              ? { timezone: event.cronConfig.timezone }
              : {}),
          },
        }
      : {}),
    // ── Trust Map / agent_handoff fields (snake_case on wire) ──
    ...(event.fromAgentId != null ? { from_agent_id: event.fromAgentId } : {}),
    ...(event.fromAgentName != null
      ? { from_agent_name: event.fromAgentName }
      : {}),
    ...(event.targetAgentId != null
      ? { target_agent_id: event.targetAgentId }
      : {}),
    ...(event.targetAgentName != null
      ? { target_agent_name: event.targetAgentName }
      : {}),
    ...(event.targetSinkId != null
      ? { target_sink_id: event.targetSinkId }
      : {}),
    ...(event.reason != null ? { reason: event.reason } : {}),
    ...(event.payloadTokenCount != null
      ? { payload_token_count: event.payloadTokenCount }
      : {}),
    ...(event.riskLevel != null ? { risk_level: event.riskLevel } : {}),
    ...(event.parentEventId != null
      ? { parent_event_id: event.parentEventId }
      : {}),
    ...(event.branchId != null ? { branch_id: event.branchId } : {}),
    ...(event.hopDepth != null ? { hop_depth: event.hopDepth } : {}),
  };
  return AuditEventV1Schema.parse(wire);
}

/**
 * Wraps `serializeForWire` and returns a record tagged with the spool sentinel
 * so on-disk events can be POSTed verbatim on replay (preserving `event_id`).
 */
export function serializeForSpool(event: AuditEvent): SerializedSpoolRecord {
  const wire = serializeForWire(event);
  return { ...wire, __wire_serialized: true };
}

/**
 * Strips the spool sentinel before re-POSTing a replayed event.
 */
export function stripSpoolSentinel(record: SerializedSpoolRecord): AuditEventV1 {
  const { __wire_serialized: _drop, ...rest } = record;
  return rest;
}
