import type { EntityKind, TokenEntry } from '../types.js';
import type { TokenVault, VaultFactory } from '../interfaces.js';
import { PriventVaultDestroyedError, PriventVaultFullError } from '../errors.js';

const DEFAULT_CAP = 10_000;

export class InMemoryTokenVault implements TokenVault {
  private readonly tokens = new Map<string, TokenEntry>();
  /** `${kind}:${normalizedValue}` → token string */
  private readonly valueIndex = new Map<string, string>();
  private readonly counters = new Map<EntityKind, number>();
  private readonly cap: number;
  private destroyed = false;

  constructor(
    readonly sessionId: string,
    private readonly defaultTtlMs?: number,
    cap = DEFAULT_CAP,
  ) {
    this.cap = cap;
  }

  async store(entry: TokenEntry): Promise<void> {
    this.assertAlive();
    if (this.tokens.size >= this.cap) {
      throw new PriventVaultFullError(this.sessionId, this.cap);
    }
    this.tokens.set(entry.token, entry);
    this.valueIndex.set(
      this.indexKey(entry.kind, entry.value),
      entry.token,
    );

    const ttl = entry.ttlMs ?? this.defaultTtlMs;
    if (ttl != null) {
      // .unref() so the timer doesn't prevent process exit in Node.js.
      const id = setTimeout(() => void this.revoke(entry.token), ttl);
      (id as unknown as { unref?: () => void }).unref?.();
    }
  }

  async retrieve(token: string): Promise<TokenEntry | null> {
    this.assertAlive();
    return this.tokens.get(token) ?? null;
  }

  async findByValue(value: string, kind: EntityKind): Promise<TokenEntry | null> {
    this.assertAlive();
    const token = this.valueIndex.get(this.indexKey(kind, value));
    if (token == null) return null;
    return this.tokens.get(token) ?? null;
  }

  async listBySession(): Promise<TokenEntry[]> {
    this.assertAlive();
    return [...this.tokens.values()];
  }

  async revoke(token: string): Promise<void> {
    const entry = this.tokens.get(token);
    if (entry == null) return;
    this.tokens.delete(token);
    this.valueIndex.delete(this.indexKey(entry.kind, entry.value));
  }

  async nextCounter(kind: EntityKind): Promise<number> {
    this.assertAlive();
    const next = (this.counters.get(kind) ?? 0) + 1;
    this.counters.set(kind, next);
    return next;
  }

  async destroy(): Promise<void> {
    this.destroyed = true;
    this.tokens.clear();
    this.valueIndex.clear();
    this.counters.clear();
  }

  private assertAlive(): void {
    if (this.destroyed) throw new PriventVaultDestroyedError(this.sessionId);
  }

  /**
   * Normalizes a raw value for the value index key.
   * EMAIL → lowercase trim; PHONE/CREDIT_CARD/IBAN → digits only; else trim.
   */
  private indexKey(kind: EntityKind, value: string): string {
    return `${kind}:${normalize(kind, value)}`;
  }
}

/** Kind-specific normalization exported for tokenizer reuse. */
export function normalize(kind: EntityKind, value: string): string {
  switch (kind) {
    case 'EMAIL':
      return value.trim().toLowerCase();
    case 'PHONE':
    case 'CREDIT_CARD':
    case 'IBAN':
      return value.replace(/\D+/g, '');
    default:
      return value.trim();
  }
}

export class InMemoryVaultFactory implements VaultFactory {
  constructor(
    private readonly defaultTtlMs?: number,
    private readonly cap = DEFAULT_CAP,
  ) {}

  create(sessionId: string): TokenVault {
    return new InMemoryTokenVault(sessionId, this.defaultTtlMs, this.cap);
  }
}
