import { createHash } from 'node:crypto';
import type {
  IExecuteFunctions,
  INodeType,
  INodeTypeDescription,
  INodeExecutionData,
} from 'n8n-workflow';
import { NodeConnectionTypes, NodeOperationError } from 'n8n-workflow';
import type { AuditEvent } from '@priventai/core';
import { scanForTokens, detokenizeDeep } from '@priventai/core';
import {
  N8nHttpVault,
  auditLog,
  buildAuditMetadata,
  getPriventBaseUrl,
  makeResolvedVault,
  resolveContext,
  safeTriggerMode,
  sha256short,
} from '../../shared/privent-http.js';

/**
 * Returns true if `url` starts with any of the given prefixes.
 * Used for trusted-sink enforcement in strict mode.
 */
function matchesTrustedSink(url: string, trusted: string[]): boolean {
  if (trusted.length === 0) return true;
  return trusted.some((prefix) => url.startsWith(prefix.trim()));
}

/**
 * Opaque, path-sensitive fingerprint of the destination URL — first 16 hex
 * chars of SHA-256(sinkUrl).  Two calls to the same URL yield the same
 * fingerprint (groupable); two paths on the same host yield different
 * fingerprints (path-level visibility for the sink catalog).  Truncation is
 * safe: the value is a non-cryptographic group key, never an auth token.
 */
export function deriveSinkId(sinkUrl: string): string | null {
  if (!sinkUrl) return null;
  return createHash('sha256').update(sinkUrl).digest('hex').slice(0, 16);
}

/**
 * Human-readable host of the destination URL (e.g. `api.salesforce.com`),
 * intended for display in the sink catalog.  Falls back to a 64-char
 * truncation so malformed URLs still surface something renderable.
 */
export function deriveSinkUrlHost(sinkUrl: string): string | null {
  if (!sinkUrl) return null;
  try {
    return new URL(sinkUrl).host;
  } catch {
    return sinkUrl.slice(0, 64);
  }
}

export class PriventDetokenize implements INodeType {
  description: INodeTypeDescription = {
    displayName: 'Privent Detokenize',
    name: 'priventDetokenize',
    icon: 'file:privent.png',
    group: ['transform'],
    version: 1,
    subtitle: '={{$parameter["targetField"]}}',
    description:
      'Resolves [KIND_NNN] placeholders back to their original values before data leaves the workflow (e.g. before an HTTP Request or database write). Place this node just before any trusted egress sink.',
    defaults: { name: 'Privent Detokenize' },
    inputs: [NodeConnectionTypes.Main],
    outputs: [NodeConnectionTypes.Main],
    credentials: [{ name: 'priventApi', required: true }],
    properties: [
      {
        displayName: 'Session ID',
        name: 'sessionId',
        type: 'string',
        default: '={{$("Privent Session").item.json.sessionId}}',
        required: true,
        description: 'Must match the session ID used by the Privent Tokenize node upstream',
      },
      {
        displayName: 'Trace ID',
        name: 'traceId',
        type: 'string',
        default: '={{ $("Privent Session").item.json.traceId }}',
        description:
          'Correlation ID from the upstream Privent Session node. Links this event to the session trace. Leave as-is; a fresh ID is generated if no Session is upstream.',
      },
      {
        displayName: 'Agent Name',
        name: 'agentName',
        type: 'string',
        default: '={{ $("Privent Session").item.json.agentName }}',
        description:
          'Logical agent identifier from the upstream Privent Session node, recorded on the audit event. Optional.',
      },
      {
        displayName: 'Target Field',
        name: 'targetField',
        type: 'string',
        default: '*',
        description:
          'Field to detokenize. Use * (default) to deep-walk and resolve tokens in the entire item JSON. Or specify a single field name (e.g. "body").',
        hint: 'The * wildcard scans every nested string in the item for tokens.',
      },
      {
        displayName: 'Strict Mode',
        name: 'strict',
        type: 'boolean',
        default: false,
        description:
          'When enabled, detokenization is blocked unless the destination URL matches the Trusted Sinks list. Tokens are left in place and an audit event is written. Use this to prevent accidental PII egress to untrusted systems.',
      },
      {
        displayName: 'Destination URL',
        name: 'sinkUrl',
        type: 'string',
        default: '',
        description: 'URL of the downstream sink (e.g. the HTTP Request node URL). Used to enforce the trusted sinks list in strict mode.',
        displayOptions: { show: { strict: [true] } },
        hint: 'Supports URL prefixes — e.g. https://api.internal.corp/',
      },
      {
        displayName: 'Trusted Sinks',
        name: 'trustedSinks',
        type: 'string',
        default: '',
        description:
          'Comma-separated list of URL prefixes allowed to receive detokenized data (e.g. https://api.internal.corp/,https://db.internal/). Only evaluated in strict mode.',
        displayOptions: { show: { strict: [true] } },
      },
      {
        displayName: 'Target Agent Name (Trust Map)',
        name: 'targetAgentName',
        type: 'string',
        default: '',
        description:
          'Optional. Canonical agent name of the downstream consumer — when set, the backend Trust Map aggregator materialises this detokenize as an A→B AgentInteraction edge instead of an A→sink edge. Leave empty for true external sinks (the InternalAgentEndpoint registry will auto-resolve in a future release).',
        hint: 'Use only when the destination URL belongs to another Privent-aware agent in the same organization.',
      },
    ],
  };

  async execute(this: IExecuteFunctions): Promise<INodeExecutionData[][]> {
    const items = this.getInputData();
    const baseUrl = await getPriventBaseUrl(this);
    const triggerMode = safeTriggerMode(this);

    const out: INodeExecutionData[] = [];

    for (let i = 0; i < items.length; i++) {
      const item = items[i]!;
      try {
        const sessionId = this.getNodeParameter('sessionId', i) as string;
        const targetField = this.getNodeParameter('targetField', i) as string;
        const strict = this.getNodeParameter('strict', i) as boolean;
        const traceIdParam = this.getNodeParameter('traceId', i, '') as string;
        const agentNameParam = this.getNodeParameter('agentName', i, '') as string;

        let sinkUrl = '';
        let isTrusted = true;
        if (strict) {
          sinkUrl = this.getNodeParameter('sinkUrl', i) as string;
          const trustedRaw = this.getNodeParameter('trustedSinks', i) as string;
          const trusted = trustedRaw.split(',').map((s) => s.trim()).filter(Boolean);
          isTrusted = matchesTrustedSink(sinkUrl, trusted);
        }

        const sinkId = deriveSinkId(sinkUrl);
        const sinkUrlHost = deriveSinkUrlHost(sinkUrl);
        const targetAgentName = (
          (this.getNodeParameter('targetAgentName', i, '') as string) ?? ''
        ).trim();
        const ctx = resolveContext(this, sessionId, traceIdParam, agentNameParam);
        const node = this.getNode();

        if (!isTrusted) {
          // Strict mode: sink not trusted — pass the item through unchanged and
          // mark it so the caller knows detokenization was skipped.
          const blockedEvent: AuditEvent = {
            type: 'detokenize',
            traceId: ctx.traceId,
            sessionId,
            timestamp: Date.now(),
            framework: 'n8n',
            workflowId: ctx.workflowId,
            nodeId: node.id,
            ...(targetAgentName ? { targetAgentName } : {}),
            metadata: buildAuditMetadata(ctx, node, {
              sink_id: sinkId,
              sink_url_host: sinkUrlHost,
              sink_trusted: false,
              strict: true,
              tokens_redeemed: 0,
              reason: 'strict-mode-block',
              ...(triggerMode !== undefined ? { trigger_mode: triggerMode } : {}),
            }),
          };
          void auditLog(this, blockedEvent, baseUrl);

          out.push({
            json: {
              ...item.json,
              privent: {
                sessionId,
                detokenized: false,
                reason: 'strict-mode: destination URL not in trusted sinks list',
              },
            },
            pairedItem: { item: i },
          });
          continue;
        }

        const vault = new N8nHttpVault(this, sessionId, baseUrl);

        const scanTarget =
          targetField === '*'
            ? item.json
            : (item.json as Record<string, unknown>)[targetField];
        const placeholders = [...scanForTokens(scanTarget)];
        const tokensRedeemed = placeholders.length;

        // Placeholder fingerprint: hashes the token placeholder strings (e.g.
        // "[EMAIL_001]|[PHONE_002]"), NOT the underlying PII values. Raw values
        // never enter the hash input — `vault.retrieve` is intentionally not
        // called for fingerprinting. See plan §B for the security rationale.
        const uniqPlaceholders = [...new Set(placeholders)].sort();
        const valueFingerprint =
          uniqPlaceholders.length > 0
            ? await sha256short(uniqPlaceholders.join(' '))
            : null;
        const valueFingerprints = await Promise.all(
          uniqPlaceholders.map((p) => sha256short(p)),
        );

        // One batch retrieve for all scanned tokens, then resolve locally so the
        // deep-walk costs zero extra round-trips.
        const entries = await vault.retrieveBatch([...new Set(placeholders)]);
        const resolvedVault = makeResolvedVault(sessionId, entries);

        let json: Record<string, unknown>;
        if (targetField === '*') {
          json = (await detokenizeDeep(item.json, resolvedVault)) as Record<string, unknown>;
        } else {
          const fieldValue = (item.json as Record<string, unknown>)[targetField];
          const resolved = await detokenizeDeep(fieldValue, resolvedVault);
          json = { ...item.json, [targetField]: resolved };
        }

        const event: AuditEvent = {
          type: 'detokenize',
          traceId: ctx.traceId,
          sessionId,
          timestamp: Date.now(),
          framework: 'n8n',
          workflowId: ctx.workflowId,
          nodeId: node.id,
          ...(targetAgentName ? { targetAgentName } : {}),
          metadata: buildAuditMetadata(ctx, node, {
            sink_id: sinkId,
            sink_url_host: sinkUrlHost,
            sink_trusted: isTrusted,
            strict,
            tokens_redeemed: tokensRedeemed,
            value_fingerprint: valueFingerprint,
            value_fingerprints: valueFingerprints,
            ...(triggerMode !== undefined ? { trigger_mode: triggerMode } : {}),
          }),
        };
        void auditLog(this, event, baseUrl);

        out.push({
          json: {
            ...json,
            privent: { sessionId, detokenized: true },
          },
          pairedItem: { item: i },
        });
      } catch (err) {
        if (this.continueOnFail()) {
          out.push({ json: { error: (err as Error).message }, pairedItem: { item: i } });
          continue;
        }
        if (err instanceof NodeOperationError) throw err;
        throw new NodeOperationError(this.getNode(), err as Error, { itemIndex: i });
      }
    }

    return [out];
  }
}
